            {
              "name": "create_game",
              "file": "game_api/functions/create_game.sql",
              "content": "-- game_api.create_game(_game_type_id citext, _players jsonb)\nCREATE OR REPLACE FUNCTION game_api.create_game(_game_type_id citext, _players jsonb)\n RETURNS game.game\n LANGUAGE plpgsql\nAS $function$\nBEGIN\n  PERFORM jwt.enforce_any_permission('{p:app-user,p:app-admin}'::citext[]);\n  RETURN game_fn.create_game(\n    jwt.tenant_id(),\n    res_fn.build_urn(jwt.tenant_id(), 'app', 'resident', jwt.resident_id()),\n    _game_type_id,\n    _players\n  );\nEND;\n$function$\n\n"
            },
            {
              "name": "game_view",
              "file": "game_api/functions/game_view.sql",
              "content": "-- game_api.game_view(_game_id uuid, _event_number integer)\nCREATE OR REPLACE FUNCTION game_api.game_view(_game_id uuid, _event_number integer DEFAULT NULL::integer)\n RETURNS jsonb\n LANGUAGE plpgsql\n STABLE\nAS $function$\nBEGIN\n  PERFORM jwt.enforce_any_permission('{p:app-user,p:app-admin}'::citext[]);\n  RETURN game_fn.player_view(\n    _game_id,\n    res_fn.build_urn(jwt.tenant_id(), 'app', 'resident', jwt.resident_id()),\n    _event_number\n  );\nEND;\n$function$\n\n"
            },
            {
              "name": "my_games",
              "file": "game_api/functions/my_games.sql",
              "content": "-- game_api.my_games(_game_type_id citext)\nCREATE OR REPLACE FUNCTION game_api.my_games(_game_type_id citext DEFAULT NULL::citext)\n RETURNS SETOF game.game\n LANGUAGE plpgsql\n STABLE\nAS $function$\nBEGIN\n  PERFORM jwt.enforce_any_permission('{p:app-user,p:app-admin}'::citext[]);\n  RETURN QUERY\n  SELECT g.*\n  FROM game.game g\n  WHERE (_game_type_id IS NULL OR g.game_type_id = _game_type_id)\n    AND EXISTS (\n      SELECT 1 FROM game.game_player gp\n      WHERE gp.game_id = g.id\n        AND gp.resident_urn = res_fn.build_urn(jwt.tenant_id(), 'app', 'resident', jwt.resident_id())\n    )\n  ORDER BY g.created_at DESC;\nEND;\n$function$\n\n"
            },
            {
              "name": "resign_game",
              "file": "game_api/functions/resign_game.sql",
              "content": "-- game_api.resign_game(_game_id uuid)\nCREATE OR REPLACE FUNCTION game_api.resign_game(_game_id uuid)\n RETURNS game.game_event\n LANGUAGE plpgsql\nAS $function$\nBEGIN\n  PERFORM jwt.enforce_any_permission('{p:app-user,p:app-admin}'::citext[]);\n  RETURN game_fn.resign_game(\n    _game_id,\n    res_fn.build_urn(jwt.tenant_id(), 'app', 'resident', jwt.resident_id())\n  );\nEND;\n$function$\n\n"
            },
            {
              "name": "submit_event",
              "file": "game_api/functions/submit_event.sql",
              "content": "-- game_api.submit_event(_game_id uuid, _event_data jsonb)\nCREATE OR REPLACE FUNCTION game_api.submit_event(_game_id uuid, _event_data jsonb)\n RETURNS game.game_event\n LANGUAGE plpgsql\nAS $function$\nBEGIN\n  PERFORM jwt.enforce_any_permission('{p:app-user,p:app-admin}'::citext[]);\n  RETURN game_fn.submit_event(\n    _game_id,\n    res_fn.build_urn(jwt.tenant_id(), 'app', 'resident', jwt.resident_id()),\n    _event_data\n  );\nEND;\n$function$\n\n"
            }
