              "content": "-- jwt.actual_resident_id()\nCREATE OR REPLACE FUNCTION jwt.actual_resident_id()\n RETURNS uuid\n LANGUAGE plpgsql\n STABLE\nAS $function$\n  DECLARE\n    _resident_id uuid;\n  BEGIN\n    _resident_id := ((jwt.jwt()->'user_metadata')->>'actual_resident_id')::uuid;\n    return _resident_id;\n  end;\n  $function$\n\n"
