              "file": "jwt/functions/display_name.sql",
              "content": "-- jwt.display_name()\nCREATE OR REPLACE FUNCTION jwt.display_name()\n RETURNS citext\n LANGUAGE plpgsql\n STABLE\nAS $function$\n  DECLARE\n    _display_name citext;\n  BEGIN\n    _display_name := (jwt.jwt()->>'display_name')::citext;\n    return _display_name;\n  end;\n  $function$\n\n"
