              "file": "msg_api/functions/deactivate_subscriber.sql",
              "content": "-- msg_api.deactivate_subscriber(_subscriber_id uuid)\nCREATE OR REPLACE FUNCTION msg_api.deactivate_subscriber(_subscriber_id uuid)\n RETURNS msg.subscriber\n LANGUAGE plpgsql\nAS $function$\n  DECLARE\n    _subscriber msg.subscriber;\n  BEGIN\n    perform jwt.enforce_permission('p:discussions');\n\n    _subscriber := msg_fn.deactivate_subscriber(\n      _subscriber_id\n    );\n    return _subscriber;\n  end;\n  $function$\n\n"
